The function takes a weighted adjacency list (a dictionary mapping each source node i to a list of (j, w) pairs, where j is a target node and w is the weight of the edge), along with a source and target node, and returns the longest path length from source to target.

```python
import networkx as nx

def find_longest_path_from_source_to_target(weighted_adj_list, source, target):
    G = nx.DiGraph()
    for src, neighbors in weighted_adj_list.items():
        for tgt, weight in neighbors:
            G.add_edge(src, tgt, weight=weight)

    topo_order = list(nx.topological_sort(G))
    dist = {node: float('-inf') for node in G.nodes}
    pred = {node: None for node in G.nodes}
    dist[source] = 0

    for u in topo_order:
        for v in G.successors(u):
            weight = G[u][v]['weight']
            if dist[u] + weight > dist[v]:
                dist[v] = dist[u] + weight
                pred[v] = u

    if dist[target] == float('-inf'):
        return None, []

    path = []
    current = target
    while current is not None:
        path.append(current)
        current = pred[current]
    path.reverse()

    return dist[target]
```
